/**
 * Webhook notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'webhook' channel.
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Configuration for the webhook adapter. */
export interface WebhookConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret for signing payloads (included as X-Webhook-Secret header). */
  secret?: string;
  /** Request timeout in milliseconds. Defaults to 5000. */
  timeoutMs?: number;
}

/**
 * Transport interface for sending HTTP requests.
 * Allows swapping between real HTTP and test/in-memory transports.
 */
export interface WebhookTransport {
  post(url: string, options: {
    headers: Record<string, string>;
    body: string;
    timeoutMs: number;
  }): Promise<{ statusCode: number; body: string }>;
}

/** Record of a webhook delivery. */
export interface SentWebhook {
  url: string;
  payload: WebhookPayloadBody;
  headers: Record<string, string>;
  sentAt: Date;
}

/** The JSON body sent in webhook POST requests. */
export interface WebhookPayloadBody {
  type: string;
  recipient: string;
  subject: string;
  body: string;
  channel: string;
  priority: string;
  metadata?: Record<string, string>;
  timestamp: string;
}

/**
 * In-memory webhook transport for testing and development.
 * Stores all sent webhooks and allows inspection.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveries: SentWebhook[] = [];

  async post(url: string, options: {
    headers: Record<string, string>;
    body: string;
    timeoutMs: number;
  }): Promise<{ statusCode: number; body: string }> {
    const payload = JSON.parse(options.body) as WebhookPayloadBody;
    this.deliveries.push({
      url,
      payload,
      headers: { ...options.headers },
      sentAt: new Date(),
    });
    return { statusCode: 200, body: '{"ok":true}' };
  }

  getDeliveries(): SentWebhook[] {
    return [...this.deliveries];
  }

  clear(): void {
    this.deliveries = [];
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private config: WebhookConfig;
  private transport: WebhookTransport;

  constructor(config: WebhookConfig, transport?: WebhookTransport) {
    this.config = config;
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a webhook notification.
   * Formats the payload as JSON and POSTs it to the configured URL.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate URL
      if (!this.config.url || !this.isValidUrl(this.config.url)) {
        const error = `Invalid webhook URL: ${this.config.url}`;
        this.logger.error(error);
        return { success: false, error };
      }

      // Format payload
      const webhookBody = this.formatPayload(payload);
      const bodyJson = JSON.stringify(webhookBody);

      // Build headers
      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
      };
      if (this.config.secret) {
        headers['X-Webhook-Secret'] = this.config.secret;
      }

      // Send via transport
      const timeoutMs = this.config.timeoutMs ?? 5000;
      this.logger.info(`Sending webhook to ${this.config.url}`);
      const response = await this.transport.post(this.config.url, {
        headers,
        body: bodyJson,
        timeoutMs,
      });

      if (response.statusCode >= 200 && response.statusCode < 300) {
        this.logger.info(`Webhook delivered successfully (${response.statusCode})`);
        return {
          success: true,
          externalId: `webhook-${Date.now()}`,
        };
      } else {
        const error = `Webhook returned status ${response.statusCode}: ${response.body}`;
        this.logger.error(error);
        return { success: false, error };
      }
    } catch (err: unknown) {
      const error = err instanceof Error ? err.message : 'Unknown webhook send error';
      this.logger.error(`Failed to send webhook: ${error}`);
      return { success: false, error };
    }
  }

  /**
   * Format the notification payload as a webhook JSON body.
   */
  private formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      priority: payload.priority,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Basic URL validation.
   */
  private isValidUrl(url: string): boolean {
    try {
      const parsed = new URL(url);
      return parsed.protocol === 'http:' || parsed.protocol === 'https:';
    } catch {
      return false;
    }
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }

  /**
   * Get all sent webhooks. Only works if using InMemoryWebhookTransport.
   */
  getSentWebhooks(): SentWebhook[] {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getDeliveries();
    }
    return [];
  }

  /**
   * Clear sent webhooks. Only works if using InMemoryWebhookTransport.
   */
  clearSentWebhooks(): void {
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clear();
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'user-123',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'webhook',
    type: 'order_confirmation',
    priority: 'normal',
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;
  const defaultUrl = 'https://hooks.example.com/notify';

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter({ url: defaultUrl }, transport);
  });

  it('should have channel set to webhook', () => {
    expect(adapter.channel).toBe('webhook');
  });

  describe('send', () => {
    it('should send a webhook and return success', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.externalId).toBeDefined();
      expect(result.externalId).toMatch(/^webhook-/);
    });

    it('should deliver payload to the transport', async () => {
      await adapter.send(makePayload());

      const deliveries = transport.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe(defaultUrl);
      expect(deliveries[0]?.payload.recipient).toBe('user-123');
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation: order-1');
      expect(deliveries[0]?.payload.type).toBe('order_confirmation');
    });

    it('should format payload as JSON with all required fields', async () => {
      await adapter.send(makePayload({ metadata: { orderId: 'order-1' } }));

      const deliveries = transport.getDeliveries();
      const payload = deliveries[0]?.payload;
      expect(payload?.type).toBe('order_confirmation');
      expect(payload?.recipient).toBe('user-123');
      expect(payload?.subject).toBeDefined();
      expect(payload?.body).toBeDefined();
      expect(payload?.channel).toBe('webhook');
      expect(payload?.priority).toBe('normal');
      expect(payload?.metadata).toEqual({ orderId: 'order-1' });
      expect(payload?.timestamp).toBeDefined();
    });

    it('should include Content-Type header', async () => {
      await adapter.send(makePayload());

      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.headers['Content-Type']).toBe('application/json');
    });

    it('should include secret header when configured', async () => {
      const secretAdapter = new WebhookAdapter(
        { url: defaultUrl, secret: 'my-secret-key' },
        transport,
      );
      await secretAdapter.send(makePayload());

      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.headers['X-Webhook-Secret']).toBe('my-secret-key');
    });

    it('should not include secret header when not configured', async () => {
      await adapter.send(makePayload());

      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.headers['X-Webhook-Secret']).toBeUndefined();
    });
  });

  describe('URL validation', () => {
    it('should reject empty URL', async () => {
      const badAdapter = new WebhookAdapter({ url: '' }, transport);
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should reject invalid URL', async () => {
      const badAdapter = new WebhookAdapter({ url: 'not-a-url' }, transport);
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should reject non-http URL', async () => {
      const badAdapter = new WebhookAdapter({ url: 'ftp://example.com/hook' }, transport);
      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should accept https URL', async () => {
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
    });

    it('should accept http URL', async () => {
      const httpAdapter = new WebhookAdapter({ url: 'http://localhost:3000/hook' }, transport);
      const result = await httpAdapter.send(makePayload());
      expect(result.success).toBe(true);
    });

    it('should not send webhook when URL is invalid', async () => {
      const badAdapter = new WebhookAdapter({ url: 'invalid' }, transport);
      await badAdapter.send(makePayload());

      expect(transport.getDeliveries()).toHaveLength(0);
    });
  });

  describe('HTTP status handling', () => {
    it('should return failure for 4xx status', async () => {
      const failTransport: WebhookTransport = {
        async post() {
          return { statusCode: 400, body: 'Bad Request' };
        },
      };
      const failAdapter = new WebhookAdapter({ url: defaultUrl }, failTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('400');
    });

    it('should return failure for 5xx status', async () => {
      const failTransport: WebhookTransport = {
        async post() {
          return { statusCode: 500, body: 'Internal Server Error' };
        },
      };
      const failAdapter = new WebhookAdapter({ url: defaultUrl }, failTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('500');
    });

    it('should succeed for 201 status', async () => {
      const okTransport: WebhookTransport = {
        async post() {
          return { statusCode: 201, body: '{"ok":true}' };
        },
      };
      const okAdapter = new WebhookAdapter({ url: defaultUrl }, okTransport);

      const result = await okAdapter.send(makePayload());
      expect(result.success).toBe(true);
    });
  });

  describe('transport error handling', () => {
    it('should return failure when transport throws', async () => {
      const failTransport: WebhookTransport = {
        async post() {
          throw new Error('Connection refused');
        },
      };
      const failAdapter = new WebhookAdapter({ url: defaultUrl }, failTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should handle non-Error thrown values', async () => {
      const failTransport: WebhookTransport = {
        async post() {
          throw 'string error';
        },
      };
      const failAdapter = new WebhookAdapter({ url: defaultUrl }, failTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown webhook send error');
    });
  });

  describe('getSentWebhooks / clearSentWebhooks', () => {
    it('should return sent webhooks from InMemoryWebhookTransport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'user-456' }));

      const sent = adapter.getSentWebhooks();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.payload.recipient).toBe('user-123');
      expect(sent[1]?.payload.recipient).toBe('user-456');
    });

    it('should clear sent webhooks', async () => {
      await adapter.send(makePayload());
      adapter.clearSentWebhooks();

      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should return empty array for non-InMemoryWebhookTransport', () => {
      const customTransport: WebhookTransport = {
        async post() {
          return { statusCode: 200, body: '{}' };
        },
      };
      const customAdapter = new WebhookAdapter({ url: defaultUrl }, customTransport);

      expect(customAdapter.getSentWebhooks()).toEqual([]);
    });
  });

  describe('getTransport', () => {
    it('should expose the transport instance', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });
});

describe('InMemoryWebhookTransport', () => {
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
  });

  it('should store sent webhooks', async () => {
    await transport.post('https://example.com/hook', {
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ type: 'test', recipient: 'user-1', subject: 'Test', body: 'Hello', channel: 'webhook', priority: 'normal', timestamp: new Date().toISOString() }),
      timeoutMs: 5000,
    });

    const deliveries = transport.getDeliveries();
    expect(deliveries).toHaveLength(1);
    expect(deliveries[0]?.url).toBe('https://example.com/hook');
    expect(deliveries[0]?.payload.type).toBe('test');
  });

  it('should clear all deliveries', async () => {
    await transport.post('https://example.com/hook', {
      headers: {},
      body: JSON.stringify({ type: 'test', recipient: 'u', subject: 's', body: 'b', channel: 'webhook', priority: 'normal', timestamp: new Date().toISOString() }),
      timeoutMs: 5000,
    });
    transport.clear();

    expect(transport.getDeliveries()).toHaveLength(0);
  });

  it('should return copies of deliveries, not references', async () => {
    await transport.post('https://example.com/hook', {
      headers: {},
      body: JSON.stringify({ type: 'test', recipient: 'u', subject: 's', body: 'b', channel: 'webhook', priority: 'normal', timestamp: new Date().toISOString() }),
      timeoutMs: 5000,
    });

    const first = transport.getDeliveries();
    const second = transport.getDeliveries();
    expect(first).not.toBe(second);
    expect(first).toEqual(second);
  });
});

